function burgerMenu(){const e=document.querySelector(".burger"),t=document.querySelector(".menu"),c=document.querySelectorAll(".menu__item-link"),i=document.querySelector("body");e.addEventListener("click",(()=>{t.classList.contains("active")?(t.classList.remove("active"),e.classList.remove("active-burger"),i.classList.remove("locked")):(t.classList.add("active"),e.classList.add("active-burger"),i.classList.add("locked"))})),c.forEach((a=>{a.addEventListener("click",(a=>{c.forEach((e=>e.classList.remove("active"))),a.target.classList.add("active"),t.classList.remove("active"),e.classList.remove("active-burger"),i.classList.remove("locked")}))})),window.addEventListener("resize",(()=>{window.innerWidth>991.98&&(t.classList.remove("active"),e.classList.remove("active-burger"),i.classList.remove("locked"))}))}function bindModal(e,t){e=document.querySelectorAll(e),t=document.querySelector(t);const c=document.body;e.forEach((e=>{e.addEventListener("click",(e=>{e.preventDefault(),t.style.display="flex",c.classList.add("locked")}))})),t.addEventListener("click",(e=>{e.target===t&&(t.style.display="none",c.classList.remove("locked"))}))}function accordion(){document.querySelectorAll(".accordion__item-trigger").forEach((e=>{e.addEventListener("click",(()=>{const t=e.parentNode;t.classList.contains("accordion__item-active")?t.classList.remove("accordion__item-active"):(document.querySelectorAll(".accordion__item").forEach((e=>e.classList.remove("accordion__item-active"))),t.classList.add("accordion__item-active"))}))}))}burgerMenu(),bindModal(".modal__btn",".modal__wrapper"),accordion(),document.querySelectorAll(".vimeo-facade").forEach((e=>{e.addEventListener("click",(()=>{const t=e.dataset.vimeoId,c=e.dataset.vimeoParams,i=document.createElement("iframe");i.src=`https://player.vimeo.com/video/${t}?${c}&autoplay=1`,i.allow="autoplay; fullscreen; picture-in-picture",i.title="Drinktank: 2 minute introduction",e.innerHTML="",e.appendChild(i)}))}));